int largestSubarrayWithSumZero(int arr[], int n) {
    struct Node* hashTable[TABLE_SIZE] = {NULL};

    int prefixSum = 0;
    int maxLen = 0;

    for (int i = 0; i < n; i++) {
        prefixSum += arr[i];

        if (prefixSum == 0) {
            maxLen = i + 1; // whole array from 0..i sums to 0
        }

        int prevIndex = search(hashTable, prefixSum);
        if (prevIndex != -1) {
            if (i - prevIndex > maxLen) {
                maxLen = i - prevIndex;
            }
        } else {
            insert(hashTable, prefixSum, i);
        }
    }
    return maxLen;
}

